import '@angular/compiler';
import { provideHttpClient } from '@angular/common/http';
import { enableProdMode } from '@angular/core';
import { bootstrapApplication } from '@angular/platform-browser';

import { AppComponent } from './app.component';

if ((window as any).ENABLE_PROD_MODE) {
    enableProdMode();
}

const app = bootstrapApplication(AppComponent, {
    providers: [provideHttpClient()],
});
```

```app.component.ts
import { Component } from "@angular/core";
import { HttpClient } from "@angular/common/http";
import { AgGridAngular } from "ag-grid-angular";
import "./styles.css";
import {
  ClientSideRowModelModule,
  ColDef,
  ColGroupDef,
  GridApi,
  GridOptions,
  GridReadyEvent,
  ModuleRegistry,
  ValidationModule,
} from "ag-grid-community";

ModuleRegistry.registerModules([
  ClientSideRowModelModule,
  ...(process.env.NODE_ENV !== "production" ? [ValidationModule] : []),
]);
import { IOlympicData } from "./interfaces";

@Component({
  selector: "my-app",
  standalone: true,
  imports: [AgGridAngular],
  template: `<div class="test-container">
    <div class="test-header">
      <button (click)="onBtSetA()">First Column Set</button>
      <button (click)="onBtSetB()">Second Column Set</button>
    </div>
    <ag-grid-angular
      style="width: 100%; height: 100%;"
      class="test-grid"
      [defaultColDef]="defaultColDef"
      [columnDefs]="columnDefs"
      [rowData]="rowData"
      (gridReady)="onGridReady($event)"
    />
  </div> `,
})
export class AppComponent {
  private gridApi!: GridApi<IOlympicData>;

  defaultColDef: ColDef = {
    initialWidth: 100,
  };
  columnDefs: (ColDef | ColGroupDef)[] = [
    {
      headerName: "Group A",
      groupId: "groupA",
      children: [
        { field: "athlete" },
        { field: "age" },
        { field: "country", columnGroupShow: "open" },
      ],
    },
    {
      headerName: "Group B",
      children: [
        { field: "sport" },
        { field: "year" },
        { field: "date", columnGroupShow: "open" },
      ],
    },
    {
      headerName: "Group C",
      groupId: "groupC",
      children: [
        { field: "total" },
        { field: "gold", columnGroupShow: "open" },
        { field: "silver", columnGroupShow: "open" },
        { field: "bronze", columnGroupShow: "open" },
      ],
    },
  ];
  rowData!: IOlympicData[];

  constructor(private http: HttpClient) {}

  onBtSetA() {
    this.gridApi.setGridOption("columnDefs", createColSetA());
  }

  onBtSetB() {
    this.gridApi.setGridOption("columnDefs", createColSetB());
  }

  onGridReady(params: GridReadyEvent<IOlympicData>) {
    this.gridApi = params.api;

    this.http
      .get<
        IOlympicData[]
      >("https://www.ag-grid.com/example-assets/olympic-winners.json")
      .subscribe((data) => {
        this.rowData = data;
      });
  }
}

function createColSetA(): ColGroupDef[] {
  return [
    {
      headerName: "Group A",
      groupId: "groupA",
      children: [
        { field: "athlete" },
        { field: "age" },
        { field: "country", columnGroupShow: "open" },
      ],
    },
    {
      headerName: "Group B",
      children: [
        { field: "sport" },
        { field: "year" },
        { field: "date", columnGroupShow: "open" },
      ],
    },
    {
      headerName: "Group C",
      groupId: "groupC",
      children: [
        { field: "total" },
        { field: "gold", columnGroupShow: "open" },
        { field: "silver", columnGroupShow: "open" },
        { field: "bronze", columnGroupShow: "open" },
      ],
    },
  ];
}
function createColSetB(): ColGroupDef[] {
  return [
    {
      headerName: "GROUP A",
      groupId: "groupA",
      children: [
        { field: "athlete" },
        { field: "age" },
        { field: "country", columnGroupShow: "open" },
      ],
    },
    {
      headerName: "Group B",
      children: [
        { field: "sport" },
        { field: "year" },
        { field: "date", columnGroupShow: "open" },
      ],
    },
    {
      headerName: "Group C",
      groupId: "groupC",
      children: [
        { field: "total" },
        { field: "gold", columnGroupShow: "open" },
        { field: "silver", columnGroupShow: "open" },
        { field: "bronze", columnGroupShow: "open" },
        { field: "extraA" },
        { field: "extraB", columnGroupShow: "open" },
      ],
    },
  ];
}
```

```interfaces.ts
export interface IOlympicData {
    athlete: string,
    age: number,
    country: string,
    year: number,
    date: string,
    sport: string,
    gold: number,
    silver: number,
    bronze: number,
    total: number
}
```

---

### columnGroupShow

```typescript
/**
 * Whether to only show the column when the group is open / closed. If not set the column is always displayed as part of the group.
 * 
 */
ColumnGroupShowType
```

---

### ColumnGroupState

```typescript
interface ColumnGroupState {
  openColumnGroupIds: string[];
};
```

---

### ColumnToolPanelState

```typescript
interface ColumnToolPanelState {
  expandedGroupIds: string[];
};
```

---

### ssrmExpandAllAffectsAllRows

```typescript
/**
 * Controls how expand/collapse operations affect all rows and group interactions.
 * If `true`, expandAll / collapseAll applies to all rows (not just loaded ones),
 * and interacting with the group overrides the default expansion state set by `isServerSideGroupOpenByDefault`.
 * 
 * @agModule RowGroupingModule / TreeDataModule
 */
boolean
```

---

### ColumnGroupOpenedEvent<TData = any, TContext = any>

```typescript
interface ColumnGroupOpenedEvent<TData = any, TContext = any> {
  columnGroup?: ProvidedColumnGroup;
  columnGroups: ProvidedColumnGroup[];
  api: GridApi<TData>;
  context: TContext;
  type: 'columnGroupOpened';
};
```

---

### _ColumnGroupGridApi

```typescript
interface _ColumnGroupGridApi {
  setColumnGroupOpened(group: ProvidedColumnGroup | string, newValue: boolean): void;
  getColumnGroup(name: string, instanceId?: number): ColumnGroup | null;
  getProvidedColumnGroup(name: string): ProvidedColumnGroup | null;
  getDisplayNameForColumnGroup(columnGroup: ColumnGroup, location: HeaderLocation): string;
  getColumnGroupState(): { groupId: string; open: boolean; }[];
  setColumnGroupState(stateItems: { groupId: string; open: boolean; }[]): void;
  resetColumnGroupState(): void;
  getLeftDisplayedColumnGroups(): (Column | ColumnGroup)[];
  getCenterDisplayedColumnGroups(): (Column | ColumnGroup)[];
  getRightDisplayedColumnGroups(): (Column | ColumnGroup)[];
  getAllDisplayedColumnGroups(): (Column | ColumnGroup)[] | null;
};
```

---

It is possible that you have column groups that are split because of pinning or the order of the columns. The grid below has only two groups that are split, displayed as many split groups. The column aligning also works here in that a change to a split group will open / close all the instances of that group in both tables.


```app.component.ts
import { HttpClient } from "@angular/common/http";
import { Component, ViewChild } from "@angular/core";

import { AgGridAngular } from "ag-grid-angular";
import type { ColDef, ColGroupDef, GridOptions } from "ag-grid-community";
import {
  AlignedGridsModule,
  ClientSideRowModelModule,
  ColumnApiModule,
  ColumnAutoSizeModule,
  ModuleRegistry,
  TextFilterModule,
  ValidationModule,
} from "ag-grid-community";

ModuleRegistry.registerModules([
  TextFilterModule,
  ColumnAutoSizeModule,
  ClientSideRowModelModule,
  AlignedGridsModule,
  ColumnApiModule,
  ...(process.env.NODE_ENV !== "production" ? [ValidationModule] : []),
]);

@Component({
  selector: "my-app",
  standalone: true,
  imports: [AgGridAngular],
  template: `
    <ag-grid-angular
      style="width: 100%; height: 45%"
      #topGrid
      [rowData]="rowData"
      [gridOptions]="topOptions"
      [columnDefs]="columnDefs"
      [alignedGrids]="[bottomGrid]"
    />

    <div style="height: 5%"></div>

    <ag-grid-angular
      style="width: 100%; height: 45%"
      #bottomGrid
      [rowData]="rowData"
      [gridOptions]="bottomOptions"
      [columnDefs]="columnDefs"
      [alignedGrids]="[topGrid]"
    />
  `,
})
export class AppComponent {
  columnDefs!: (ColDef | ColGroupDef)[];
  rowData!: any[];
  topOptions: GridOptions = {
    defaultColDef: {
      minWidth: 120,
    },
    autoSizeStrategy: {
      type: "fitGridWidth",
    },
  };
  bottomOptions: GridOptions = {
    defaultColDef: {
      flex: 1,
      minWidth: 120,
    },
  };

  @ViewChild("topGrid") topGrid!: AgGridAngular;

  constructor(private http: HttpClient) {
    this.columnDefs = [
      {
        headerName: "Group 1",
        groupId: "Group1",
        children: [
          { field: "athlete", pinned: true, width: 100 },
          { field: "age", pinned: true, columnGroupShow: "open", width: 100 },
          { field: "country", width: 100 },
          { field: "year", columnGroupShow: "open", width: 100 },
          { field: "date", width: 100 },
          { field: "sport", columnGroupShow: "open", width: 100 },
          { field: "date", width: 100 },
          { field: "sport", columnGroupShow: "open", width: 100 },
        ],
      },
      {
        headerName: "Group 2",
        groupId: "Group2",
        children: [
          { field: "athlete", pinned: true, width: 100 },
          { field: "age", pinned: true, columnGroupShow: "open", width: 100 },
          { field: "country", width: 100 },
          { field: "year", columnGroupShow: "open", width: 100 },
          { field: "date", width: 100 },
          { field: "sport", columnGroupShow: "open", width: 100 },
          { field: "date", width: 100 },
          { field: "sport", columnGroupShow: "open", width: 100 },
        ],
      },
    ];
  }

  ngOnInit() {
    this.http
      .get("https://www.ag-grid.com/example-assets/olympic-winners.json")
      .subscribe((data) => {
        this.rowData = data as any[];

        // mix up some columns
        this.topGrid.api.moveColumnByIndex(11, 4);
        this.topGrid.api.moveColumnByIndex(11, 4);
      });
  }
}
```

