import type { ColumnState } from 'ag-grid-community';

/** Maps mistaken / legacy persisted colIds to the grid `colId`. */
function normalizeRfqColId(colId: string): string {
  if (colId === 'Factory_updated') {
    return 'factory_updated';
  }
  return colId;
}

/** * RFQ grid column **order** is defined by `RFQ_COLUMN_HEADERS_CONFIG` ŌåÆ `colHeaders` array order
 * in `rfq.grid.config.ts` (after role filtering in the component). This function builds the
 * `ColumnState[]` passed to `applyColumnState({ applyOrder: true })` so the UI column order
 * always matches that list.
 *
 * Per-column settings from persistence (`getColumnState` / saved views / session), such as
 * `hide`, `width`, `pinned`, and `sort`, are preserved when a `colId` exists in both the
 * config headers and the saved state. Any `order` field is stripped so array order wins.
 */
export function buildRfqColumnStateInConfigOrder(
  colHeaders: any[] | null | undefined,
  savedColumnState: ColumnState[] | null | undefined
): ColumnState[] {
  if (!Array.isArray(colHeaders) || colHeaders.length === 0) {
    return Array.isArray(savedColumnState) ? [...savedColumnState] : [];
  }

  const savedMap = new Map<string, ColumnState>();
  for (const s of savedColumnState ?? []) {
    if (!s?.colId) {
      continue;
    }
    const id = normalizeRfqColId(String(s.colId));
    if (!savedMap.has(id)) {
      savedMap.set(id, { ...s, colId: id });
    }
  }

  const result: ColumnState[] = [];
  for (const col of colHeaders) {
    if (!col || typeof col !== 'object') {
      continue;
    }
    const colId = normalizeRfqColId(String(col.colId || col.field));
    if (!colId) {
      continue;
    }

    const saved = savedMap.get(colId);
    if (saved) {
      const { order: _order, ...rest } = saved as ColumnState & { order?: number };
      result.push(rest as ColumnState);
    } else {
      result.push({ colId, hide: !!col.hide });
    }
  }
  return result;
}

