  }
  _filter(value: unknown) {
    const filterValue = (value == null ? '' : String(value)).toLowerCase();
    return this.colHeaders.filter(col =>
      (col.colId != null) && String(col.colId).toLowerCase().includes(filterValue)
    );
  }
  async onClick(select: MatSelect) {
    if (!this.gridApi?.getColumnState) {
      this._snakcbar.open('Grid is not ready yet.', 'close');
      return;
    }

    this.selectedHeaders = []
    this.colHeaders = []

    const allState = this.gridApi.getColumnState();
    const colHeaders = allState.map((state, index) => ({
      colId: state.colId,
      hide: state.hide,
      pinned: state.pinned,
      width: state.width,
      flex: state.flex,
      sort: state.sort,
      sortIndex: state.sortIndex,
      order: index,
      layout_name: this.selectedView?.layout_name,
    }));
    colHeaders.forEach(element => {
      if (element.hide == false) {
        this.selectedHeaders.push(element.colId)
      }
    });
    this.colHeaders = colHeaders

    this.filteredOptions = this.inputControl.valueChanges.pipe(
      startWith(''),
      map((value) => this._filter(value))
    );

    setTimeout(() => select.open(), 0);
  }
  async onSave() {
    if (!this.gridApi?.getColumnState) {
      this._snakcbar.open('Grid is not ready yet.', 'close');
      return;
    }
    if (this.selectedView.layout_name != 'Default' && this.selectedView.layout_name != null || this.selectedView.layout_name != null && this.role == 'admin') {
      const allState = this.gridApi.getColumnState();
      const orderAndVisibilityState = allState.map((state, index) => ({
        colId: state.colId,
        hide: state.hide,
        pinned: state.pinned,
        width: state.width,
        order: index,
        layout_name: this.selectedView.layout_name,
        field: state.colId,
        grid_id: this.gridId
      }));
      try {
        const data: any = await firstValueFrom(this.itemService.saveGridLayout(orderAndVisibilityState));
        this._snakcbar.open(`Current view was saved successfully.`, 'close')
      } catch (err) {
        console.error('[LayoutDropdown] saveGridLayout failed:', err);
      }
    } else {
      this._snakcbar.open(`You can't save on Default view. Please select a diffrent view or create a new one.`, 'close')
    }
  }
}

