521	  private applyGridViewStateForViewName(layoutName: string): void {
522	    if (!this.gridApi || !layoutName) {
523	      return;
524	    }
525	    this.itemService.getGridViewState({ grid_id: 'rfq', view_name: layoutName }).subscribe((res: any) => {
526	      if (res) {
527	        if (res.column_state && res.column_state.length > 0) {
528	          // If the saved state has no explicit sort on the auto-group column (e.g. it was
529	          // saved before the date-based sort was introduced), default it to 'desc' so groups
530	          // always load newest-first unless the user deliberately saved a different direction.
531	          const AUTO_GROUP_COL = 'ag-Grid-AutoColumn';
532	          const savedAutoGroupSort = res.column_state.find((s: any) => s.colId === AUTO_GROUP_COL)?.sort;
533	          const state = savedAutoGroupSort
534	            ? res.column_state
535	            : [
536	                ...res.column_state.filter((s: any) => s.colId !== AUTO_GROUP_COL),
537	                { colId: AUTO_GROUP_COL, sort: 'desc' }
538	              ];
539	          this.gridApi.applyColumnState({ state, applyOrder: true });
540	          this._saveViewStateToSession();
541	        }
542	        const fm = res.filter_model;
543	        const hasFilterModel = fm && typeof fm === 'object' && Object.keys(fm).length > 0;
544	        if (hasFilterModel) {
545	          setTimeout(() => {
546	            this.gridApi.setFilterModel(fm);
547	            this._saveViewStateToSession();
548	            this.afterViewFilterAppliedForDefaultStep(res);
549	          }, 200);
550	        } else {
551	          this.afterViewFilterAppliedForDefaultStep(res);
552	        }
553	      } else {
554	        this.itemService
555	          .getSelectedGridView({ layout_name: layoutName, grid_id: 'rfq' })
556	          .subscribe(async (legacyRes: any) => {
557	            if (legacyRes.length > 0) {
558	              const currentColIds = new Set(this.gridApi.getColumns().map((col) => col.getColId()));
559	              const savedColIds = new Set(legacyRes.map((s: any) => s.colId));
560	              const validState = legacyRes.filter((s: any) => currentColIds.has(s.colId));
561	              const newCols = this.colHeaders
