private applyGridViewStateForViewName(layoutName: string): void {
  if (!this.gridApi || !layoutName) {
    return;
  }
  this.itemService.getGridViewState({ grid_id: 'rfq', view_name: layoutName }).subscribe((res: any) => {
    if (res) {
      if (res.column_state && res.column_state.length > 0) {
        // If the saved state has no explicit sort on the auto-group column (e.g. it was
        // saved before the date-based sort was introduced), default it to 'desc' so groups
        // always load newest-first unless the user deliberately saved a different direction.
        const AUTO_GROUP_COL = 'ag-Grid-AutoColumn';
        const savedAutoGroupSort = res.column_state.find((s: any) => s.colId === AUTO_GROUP_COL)?.sort;
        const state = savedAutoGroupSort
          ? res.column_state
          : [
              ...res.column_state.filter((s: any) => s.colId !== AUTO_GROUP_COL),
              { colId: AUTO_GROUP_COL, sort: 'desc' }
            ];
        this.gridApi.applyColumnState({ state, applyOrder: true });
        this._saveViewStateToSession();
      }
      const fm = res.filter_model;
      const hasFilterModel = fm && typeof fm === 'object' && Object.keys(fm).length > 0;
      if (hasFilterModel) {
        setTimeout(() => {
          this.gridApi.setFilterModel(fm);
          this._saveViewStateToSession();
          this.afterViewFilterAppliedForDefaultStep(res);
        }, 200);
      } else {
        this.afterViewFilterAppliedForDefaultStep(res);
      }
    } else {
      this.itemService
        .getSelectedGridView({ layout_name: layoutName, grid_id: 'rfq' })
        .subscribe(async (legacyRes: any) => {
          if (legacyRes.length > 0) {
            const currentColIds = new Set(this.gridApi.getColumns().map((col) => col.getColId()));
            const savedColIds = new Set(legacyRes.map((s: any) => s.colId));
            const validState = legacyRes.filter((s: any) => currentColIds.has(s.colId));
            const newCols = this.colHeaders
              .filter((col: any) => {
                const colId = col.colId || col.field;
                return currentColIds.has(colId) && !savedColIds.has(colId);
              })
              .map((col: any, i: number) => ({
                colId: col.colId || col.field,
                hide: false,
                order: Math.max(...validState.map((s: any) => s.order || 0), -1) + 1 + i
              }));
            this.gridApi.applyColumnState({ state: [...validState, ...newCols], applyOrder: true });
            this._saveViewStateToSession();
          }
          this.afterViewFilterAppliedForDefaultStep({ filter_model: null });
        });
    }
  });
}

/** Role may not be on the component yet when the grid first renders (verifyRole is async). */
private getEffectiveRole(): string | undefined {
  return this.role || (typeof window !== 'undefined' ? (window as any)['role'] : undefined);
}

/**
 * Saved grid views call setFilterModel after firstDataRendered, which wipes the Step filter
 * set in onFirstDataRendered. Re-apply default Step when the saved model has no `step` entry.
 */
private afterViewFilterAppliedForDefaultStep(viewRes: { filter_model?: any }): void {
  if (!this.gridApi) {
    return;
  }
  const role = this.getEffectiveRole();
  if (!role || (role !== 'admin' && role !== 'production' && role !== 'designer')) {
    return;
  }
  const saved = viewRes?.filter_model;
  const hasStepKey = saved && typeof saved === 'object' && Object.prototype.hasOwnProperty.call(saved, 'step');
  if (hasStepKey) {
    return;
  }
  this.applyDefaultStepFilter(() => {
    this.applyRfqMasterDetailExpansionDefaults(this.gridApi);
    setTimeout(() => this.applyRfqMasterDetailExpansionDefaults(this.gridApi), 0);
  }, role);
}

hasRfqDefaultView(): boolean {
