const Sequelize = require('sequelize');
module.exports = function(sequelize, DataTypes) {
  return sequelize.define('GridViewState', {
    id: {
      autoIncrement: true,
      autoIncrementIdentity: true,
      type: DataTypes.INTEGER,
      allowNull: false,
      primaryKey: true
    },
    user_id_fk: {
      type: DataTypes.INTEGER,
      allowNull: true,
      comment: 'Foreign key to user. Null for Default views.'
    },
    grid_id: {
      type: DataTypes.STRING(100),
      allowNull: false,
      comment: 'Grid identifier (e.g., itemLibrary, artPiece, licensingTracking)'
    },
    view_name: {
      type: DataTypes.STRING(255),
      allowNull: false,
      comment: 'Name of the view'
    },
    column_state: {
      type: DataTypes.JSONB,
      allowNull: true,
      comment: 'JSON storing AG Grid column state (width, pinned, hide, order)'
    },
    filter_model: {
      type: DataTypes.JSONB,
      allowNull: true,
      comment: 'JSON storing AG Grid filter model'
    },
    is_default: {
      type: DataTypes.BOOLEAN,
      allowNull: false,
      defaultValue: false,
      comment: 'User default view for this grid (at most one true per user_id_fk + grid_id)'
    },
    created_at: {
      type: DataTypes.DATE,
      allowNull: true,
      defaultValue: Sequelize.literal('CURRENT_TIMESTAMP')
    },
    updated_at: {
      type: DataTypes.DATE,
      allowNull: true,
      defaultValue: Sequelize.literal('CURRENT_TIMESTAMP')
    }
  }, {
    sequelize,
    tableName: 'GridViewState',
    timestamps: false,
    indexes: [
      {
        name: "GridViewState_pkey",
        unique: true,
        fields: [
          { name: "id" },
        ]
      },
      {
        name: "GridViewState_user_grid_view",
        unique: true,
        fields: [
          { name: "user_id_fk" },
          { name: "grid_id" },
          { name: "view_name" }
        ]
      }
    ]
  });
};

