import type { ColDef, ColGroupDef } from 'ag-grid-community';

/**
 * RFQ pricing column grouping.
 *
 * The RFQ grid has 28 pricing columns that form 8 logical groups ŌĆö the cross of
 * {Gen, Lic} ├Ś {FOB, POE, Whse, mDDP}. Each pricing column is already tagged in
 * `rfq.grid.config.ts` with a `headerClass` marker of the form `group-header-<suffix>`
 * (e.g. `group-header-gen-fob`). This module reads that marker and wraps consecutive
 * columns sharing a marker into an AG Grid Column Group (`ColGroupDef`) so users can
 * collapse/expand each group.
 *
 * IMPORTANT: this transform runs as the LAST step when building the grid `columnDefs`
 * ŌĆö i.e. AFTER role filtering and auto-formatters have run on the flat column list.
 * Keeping the source config flat means the existing flat-array code paths
 * (`filterColumnsByRole`, `applyAutoFormatters`, the layout-dropdown column filter,
 * `buildRfqColumnStateInConfigOrder`) are untouched. Column open/closed state is a
 * separate concern persisted via `api.getColumnGroupState()` / `setColumnGroupState()`.
 */

/** Marker prefix used on RFQ pricing columns in `rfq.grid.config.ts`. */
const GROUP_HEADER_PREFIX = 'group-header-';

/**
 * Human-readable group headers keyed by the `headerClass` marker suffix.
 * Only suffixes listed here are grouped; any other column passes through untouched.
 */
export const RFQ_PRICING_GROUP_LABELS: Readonly<Record<string, string>> = {
  'gen-fob': 'Gen FOB',
  'gen-poe': 'Gen POE',
  'gen-whse': 'Gen Whse',
  'gen-mddp': 'Gen mDDP',
  'lic-fob': 'Lic FOB',
  'lic-poe': 'Lic POE',
  'lic-whse': 'Lic Whse',
  'lic-mddp': 'Lic mDDP',
};

/**
 * Stable `groupId` for AG Grid column-group open/closed persistence.
 * Must stay constant across reloads so saved group state re-applies correctly.
 */
export function rfqPricingGroupId(markerSuffix: string): string {
  return `grp_${markerSuffix.replace(/-/g, '_')}`;
}

/** Extract the `gen-fob` style suffix from a column's `headerClass`, or null if not a pricing column. */
function pricingGroupSuffix(col: any): string | null {
  const hc = col?.headerClass;
  const classes = Array.isArray(hc) ? hc : typeof hc === 'string' ? [hc] : [];
  for (const c of classes) {
    if (typeof c === 'string' && c.startsWith(GROUP_HEADER_PREFIX)) {
      return c.slice(GROUP_HEADER_PREFIX.length);
    }
  }
  return null;
}

/**
 * True when a column should remain visible while its group is collapsed ŌĆö the
 * "summary" column. For RFQ that is the "Price for Sales" column of each group,
 * whose colId ends with `_price_sales`.
 */
export function isAlwaysVisiblePricingColumn(col: any): boolean {
  const colId = String(col?.colId ?? col?.field ?? '');
  return colId.endsWith('_price_sales');
}

/**
 * Wrap the 8 RFQ pricing groups into `ColGroupDef`s, leaving every non-pricing
 * column exactly where it was. Config order is preserved; grouped columns are
 * always contiguous in the source config, so grouping never reorders anything.
 *
 * Group behaviour:
 *  - `openByDefault: true`  ŌåÆ groups start expanded (nothing collapsed by default).
 *  - `marryChildren: true`  ŌåÆ a group's columns can't be dragged apart.
 *  - "Price for Sales" child stays always-visible (no `columnGroupShow`); the other
 *    children get `columnGroupShow: 'open'` so they only show when the group is open.
 */
export function groupRfqPricingColumns(
  cols: Array<ColDef | ColGroupDef | any> | null | undefined
): Array<ColDef | ColGroupDef> {
  if (!Array.isArray(cols)) {
    return [];
  }

  const out: Array<ColDef | ColGroupDef> = [];
  let i = 0;
  while (i < cols.length) {
    const suffix = pricingGroupSuffix(cols[i]);

    // Non-pricing column (or an unknown marker): pass through untouched.
    if (!suffix || !RFQ_PRICING_GROUP_LABELS[suffix]) {
      out.push(cols[i]);
      i++;
      continue;
    }

    // Gather every consecutive column sharing this group marker.
    const children: ColDef[] = [];
    while (i < cols.length && pricingGroupSuffix(cols[i]) === suffix) {
      const child: any = { ...cols[i] };
      if (isAlwaysVisiblePricingColumn(child)) {
        // Summary column: always visible regardless of open/closed state.
        delete child.columnGroupShow;
      } else {
        child.columnGroupShow = 'open';
      }
      children.push(child);
      i++;
    }

    out.push({
      headerName: RFQ_PRICING_GROUP_LABELS[suffix],
      groupId: rfqPricingGroupId(suffix),
      marryChildren: true,
      openByDefault: true,
      children,
    } as ColGroupDef);
  }

  return out;
}

