import { describe, expect, it } from '@jest/globals';
import type { ColumnState } from 'ag-grid-community';
import { buildRfqColumnStateInConfigOrder } from './rfq-grid-column-display-order';

describe('buildRfqColumnStateInConfigOrder', () => {
  it('orders column state exactly like colHeaders', () => {
    const colHeaders = [
      { colId: 'step', hide: false },
      { colId: 'factory_updated', hide: false },
      { colId: 'material', hide: false }
    ];
    const saved: ColumnState[] = [
      { colId: 'material', hide: true, width: 400 },
      { colId: 'step', hide: false, width: 100 }
    ];
    const out = buildRfqColumnStateInConfigOrder(colHeaders, saved);
    expect(out.map((c) => c.colId)).toEqual(['step', 'factory_updated', 'material']);
  });

  it('preserves saved props and strips order', () => {
    const colHeaders = [{ colId: 'a' }, { colId: 'b' }];
    const saved: ColumnState[] = [
      { colId: 'b', hide: true, width: 50, order: 99 } as ColumnState & { order: number },
      { colId: 'a', pinned: 'left' as const }
    ];
    const out = buildRfqColumnStateInConfigOrder(colHeaders, saved);
    expect(out[0]).toMatchObject({ colId: 'a', pinned: 'left' });
    expect(out[0]).not.toHaveProperty('order');
    expect(out[1]).toMatchObject({ colId: 'b', hide: true, width: 50 });
  });

  it('uses colDef hide for columns missing from saved state', () => {
    const colHeaders = [{ colId: 'x', hide: true }, { colId: 'y', hide: false }];
    const out = buildRfqColumnStateInConfigOrder(colHeaders, []);
    expect(out).toEqual([
      { colId: 'x', hide: true },
      { colId: 'y', hide: false }
    ]);
  });

  it('normalizes Factory_updated colId from saved state', () => {
    const colHeaders = [{ colId: 'factory_updated', hide: false }];
    const saved = [{ colId: 'Factory_updated', hide: true } as ColumnState];
    const out = buildRfqColumnStateInConfigOrder(colHeaders, saved);
    expect(out[0]).toMatchObject({ colId: 'factory_updated', hide: true });
  });
});

