import { describe, expect, it } from '@jest/globals';
import type { ColDef, ColGroupDef } from 'ag-grid-community';
import {
  groupRfqPricingColumns,
  isAlwaysVisiblePricingColumn,
  rfqPricingGroupId,
  RFQ_PRICING_GROUP_LABELS,
} from './rfq-column-groups';

/** Build a flat pricing column the way rfq.grid.config.ts does (headerClass marker + colId). */
function priceCol(colId: string, marker: string): ColDef {
  return { field: colId, colId, headerClass: `group-header-${marker}` } as ColDef;
}

/** The 8 groups as they appear in config order. */
const GEN_SUFFIXES = ['gen-fob', 'gen-poe', 'gen-whse', 'gen-mddp'];
const LIC_SUFFIXES = ['lic-fob', 'lic-poe', 'lic-whse', 'lic-mddp'];

function genGroupCols(marker: string): ColDef[] {
  const base = marker.replace(/-/g, '_');
  return [
    priceCol(`${base}_sell_price`, marker),
    priceCol(`${base}_margin`, marker),
    priceCol(`${base}_price_sales`, marker),
  ];
}

function licGroupCols(marker: string): ColDef[] {
  const base = marker.replace(/-/g, '_');
  return [
    priceCol(`${base}_royalty`, marker),
    priceCol(`${base}_sell_price`, marker),
    priceCol(`${base}_margin`, marker),
    priceCol(`${base}_price_sales`, marker),
  ];
}

function isGroup(def: ColDef | ColGroupDef): def is ColGroupDef {
  return Array.isArray((def as ColGroupDef).children);
}

describe('rfqPricingGroupId', () => {
  it('produces a stable snake_case groupId', () => {
    expect(rfqPricingGroupId('gen-fob')).toBe('grp_gen_fob');
    expect(rfqPricingGroupId('lic-mddp')).toBe('grp_lic_mddp');
  });
});

describe('isAlwaysVisiblePricingColumn', () => {
  it('is true only for the "price for sales" summary column', () => {
    expect(isAlwaysVisiblePricingColumn({ colId: 'gen_fob_price_sales' })).toBe(true);
    expect(isAlwaysVisiblePricingColumn({ colId: 'gen_fob_sell_price' })).toBe(false);
    expect(isAlwaysVisiblePricingColumn({ colId: 'lic_fob_royalty' })).toBe(false);
  });

  it('falls back to field when colId is absent', () => {
    expect(isAlwaysVisiblePricingColumn({ field: 'lic_poe_price_sales' })).toBe(true);
  });
});

describe('groupRfqPricingColumns', () => {
  it('returns [] for non-array input', () => {
    expect(groupRfqPricingColumns(null)).toEqual([]);
    expect(groupRfqPricingColumns(undefined)).toEqual([]);
  });

  it('leaves non-pricing columns untouched and ungrouped', () => {
    const flat = [
      { colId: 'desc', field: 'Description' },
      { colId: 'quantity', field: 'Quantity' },
    ];
    const out = groupRfqPricingColumns(flat);
    expect(out).toHaveLength(2);
    expect(out.every((c) => !isGroup(c))).toBe(true);
    expect(out[0]).toBe(flat[0]); // passed through by reference
  });

  it('forms exactly 8 groups from the full pricing set', () => {
    const flat: ColDef[] = [
      { colId: 'desc', field: 'Description' } as ColDef,
      ...GEN_SUFFIXES.flatMap(genGroupCols),
      ...LIC_SUFFIXES.flatMap(licGroupCols),
      { colId: 'note', field: 'Notes' } as ColDef,
    ];
    const out = groupRfqPricingColumns(flat);
    const groups = out.filter(isGroup);
    expect(groups).toHaveLength(8);
    expect(groups.map((g) => g.headerName)).toEqual([
      'Gen FOB',
      'Gen POE',
      'Gen Whse',
      'Gen mDDP',
      'Lic FOB',
      'Lic POE',
      'Lic Whse',
      'Lic mDDP',
    ]);
    // Non-pricing columns stay flat and in place (first and last).
    expect(isGroup(out[0])).toBe(false);
    expect(isGroup(out[out.length - 1])).toBe(false);
  });

  it('assigns stable groupIds and open-by-default expansion', () => {
    const out = groupRfqPricingColumns(genGroupCols('gen-fob'));
    const group = out[0] as ColGroupDef;
    expect(group.groupId).toBe('grp_gen_fob');
    expect(group.openByDefault).toBe(true);
    expect(group.marryChildren).toBe(true);
  });

  it('keeps "price for sales" always visible and hides the rest until open', () => {
    const out = groupRfqPricingColumns(licGroupCols('lic-fob'));
    const group = out[0] as ColGroupDef;
    const children = group.children as ColDef[];
    expect(children).toHaveLength(4);

    const priceForSales = children.find((c) => c.colId === 'lic_fob_price_sales')!;
    const royalty = children.find((c) => c.colId === 'lic_fob_royalty')!;
    const sell = children.find((c) => c.colId === 'lic_fob_sell_price')!;
    const margin = children.find((c) => c.colId === 'lic_fob_margin')!;

    expect(priceForSales.columnGroupShow).toBeUndefined();
    expect(royalty.columnGroupShow).toBe('open');
    expect(sell.columnGroupShow).toBe('open');
    expect(margin.columnGroupShow).toBe('open');
  });

  it('groups a role-filtered set where only the summary column survives', () => {
    // Sales/designer users only see the "price for sales" column of each group.
    const flat = [
      priceCol('gen_fob_price_sales', 'gen-fob'),
      priceCol('gen_poe_price_sales', 'gen-poe'),
    ];
    const out = groupRfqPricingColumns(flat);
    const groups = out.filter(isGroup);
    expect(groups).toHaveLength(2);
    // Single always-visible child, nothing hidden ŌĆö the group still renders its header.
    const first = groups[0];
    expect(first.children).toHaveLength(1);
    expect((first.children[0] as ColDef).columnGroupShow).toBeUndefined();
  });

  it('does not merge two different groups that sit next to each other', () => {
    const flat = [
      priceCol('gen_fob_sell_price', 'gen-fob'),
      priceCol('gen_fob_price_sales', 'gen-fob'),
      priceCol('gen_poe_sell_price', 'gen-poe'),
      priceCol('gen_poe_price_sales', 'gen-poe'),
    ];
    const groups = groupRfqPricingColumns(flat).filter(isGroup);
    expect(groups).toHaveLength(2);
    expect(groups[0].groupId).toBe('grp_gen_fob');
    expect(groups[1].groupId).toBe('grp_gen_poe');
  });

  it('does not mutate the input column objects', () => {
    const col = priceCol('gen_fob_sell_price', 'gen-fob');
    groupRfqPricingColumns([col]);
    expect(col).not.toHaveProperty('columnGroupShow');
  });

  it('exposes a label for every one of the 8 markers', () => {
    expect(Object.keys(RFQ_PRICING_GROUP_LABELS)).toHaveLength(8);
  });
});

