Customer.saveGridViewState = async (req, result) => {
  try {
    let user_info = await getUserInfo(req.headers.authorization);
    let userDetail = await findUserInfoWithEmail(user_info);

    if (!userDetail && user_info.role === 'vendor') {
      userDetail = await findVendorInfoWithEmail(user_info);
      if (userDetail) userDetail.id = userDetail.vendor_id;
    }

    const { grid_id, view_name, column_state, filter_model } = req.body;

    // No one can save to Default view
    if (view_name === 'Default') {
      return result({ message: 'Cannot modify the Default view.' }, null);
    }

    // Determine user_id: null for Default view, user's id otherwise
    let userId = null;
    if (view_name !== 'Default' || user_info.role !== 'admin') {
      userId = userDetail?.id || null;
    }

    const [viewState, created] = await sql.GridViewState.findOrCreate({
      where: {
        user_id_fk: userId,
        grid_id: grid_id,
        view_name: view_name
      },
      defaults: {
        user_id_fk: userId,
        grid_id: grid_id,
        view_name: view_name,
        column_state: column_state,
        filter_model: filter_model,
        is_default: false,
        created_at: new Date(),
        updated_at: new Date()
      }
    });

    if (!created) {
      await sql.GridViewState.update({
        column_state: column_state,
        filter_model: filter_model,
        updated_at: new Date()
      }, {
        where: {
          user_id_fk: userId,
          grid_id: grid_id,
          view_name: view_name
        },
        individualHooks: true
      });
    }

    result(null, { success: true, created: created });
  } catch (err) {
    console.error('Error saving grid view state:', err);
    result(err, null);
  }
};

/**
