db =  require('./db/init-models')(sequelize);

sequelize.sync();

// Safe one-time migrations: ADD COLUMN IF NOT EXISTS never fails on re-deploy
const schema = process.env.SCHEMA ? `"${process.env.SCHEMA}".` : '';
sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_duty_rate_equation" VARCHAR(500)`)
  .catch(err => console.warn('Migration rfqItem_duty_rate_equation skipped:', err.message));
sequelize.query(`ALTER TABLE ${schema}"customers" ADD COLUMN IF NOT EXISTS customers_logo VARCHAR(500)`)
  .catch(err => console.warn('Migration customers_logo skipped:', err.message));
sequelize.query(`CREATE TABLE IF NOT EXISTS ${schema}app_settings (key VARCHAR(100) PRIMARY KEY, value TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())`)
  .catch(err => console.warn('Migration app_settings skipped:', err.message));
// AI cache telemetry events ŌĆö append-only per backend response. Admin AI Settings
// aggregates this table to show whether prompt/context caching is actually paying off.
sequelize.query(`CREATE TABLE IF NOT EXISTS ${schema}ai_cache_events (
  id UUID PRIMARY KEY,
  feature VARCHAR(80) NOT NULL DEFAULT 'unknown',
  provider VARCHAR(40) NOT NULL,
  api_backend VARCHAR(40) NOT NULL,
  model VARCHAR(160) NOT NULL,
  cache_strategy VARCHAR(40) NOT NULL,
  session_id VARCHAR(160),
  telemetry_available BOOLEAN NOT NULL DEFAULT false,
  prompt_tokens INTEGER NOT NULL DEFAULT 0,
  cache_hit_tokens INTEGER NOT NULL DEFAULT 0,
  cache_miss_tokens INTEGER NOT NULL DEFAULT 0,
  cache_creation_tokens INTEGER NOT NULL DEFAULT 0,
  completion_tokens INTEGER NOT NULL DEFAULT 0,
  reasoning_tokens INTEGER NOT NULL DEFAULT 0,
  total_tokens INTEGER NOT NULL DEFAULT 0,
  cache_hit_rate_pct DOUBLE PRECISION NOT NULL DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
)`).catch(err => console.warn('Migration ai_cache_events skipped:', err.message));
sequelize.query(`CREATE INDEX IF NOT EXISTS ai_cache_events_created_at_idx ON ${schema}ai_cache_events (created_at DESC)`)
  .catch(err => console.warn('Migration ai_cache_events_created_at_idx skipped:', err.message));
sequelize.query(`CREATE INDEX IF NOT EXISTS ai_cache_events_feature_created_at_idx ON ${schema}ai_cache_events (feature, created_at DESC)`)
  .catch(err => console.warn('Migration ai_cache_events_feature_created_at_idx skipped:', err.message));
sequelize.query(`ALTER TABLE ${schema}"users" ADD COLUMN IF NOT EXISTS profile_photo TEXT`)
  .catch(err => console.warn('Migration users.profile_photo skipped:', err.message));
// users.graph_photo ŌĆö cached M365/Teams profile photo URL (DO Spaces) pulled
// from Microsoft Graph. Distinct from profile_photo so a user-uploaded photo
// always takes precedence. graph_photo_synced_at throttles re-fetching (and is
// stamped even when the user has no Graph photo, to avoid hammering Graph).
sequelize.query(`ALTER TABLE ${schema}"users" ADD COLUMN IF NOT EXISTS graph_photo TEXT`)
  .catch(err => console.warn('Migration users.graph_photo skipped:', err.message));
sequelize.query(`ALTER TABLE ${schema}"users" ADD COLUMN IF NOT EXISTS graph_photo_synced_at TIMESTAMPTZ`)
  .catch(err => console.warn('Migration users.graph_photo_synced_at skipped:', err.message));
// vendor.vendor_profile_photo ŌĆö factory (vendor) users live in the vendor table,
// not users, so /api/user/me and /api/user/photo read/store their avatar here.
sequelize.query(`ALTER TABLE ${schema}"vendor" ADD COLUMN IF NOT EXISTS vendor_profile_photo TEXT`)
  .catch(err => console.warn('Migration vendor.vendor_profile_photo skipped:', err.message));
// RFQItem.price_sales_snapshots ŌĆö per-row JSON map of price_sales colId ->
// {duty_rate, duty_dollar, container_price, at}, snapshotting the cost inputs at
// the moment each "Price for Sales" cell was last populated (shown as a cell tooltip).
sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_price_sales_snapshots" TEXT`)
  .catch(err => console.warn('Migration rfqItem_price_sales_snapshots skipped:', err.message));
// RFQItem.factories_step_at ŌĆö timestamp for when an item moves to @factories.
// The mixed-case identifier must be quoted to match Sequelize's generated SQL.
sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_factories_step_at" TIMESTAMPTZ`)
  .catch(err => console.warn('Migration rfqItem_factories_step_at skipped:', err.message));

      .catch(err => console.warn('Migration RFQVendor.RFQVendor_archive_optout skipped:', err.message));
    // Factory.factory_country ŌĆö country where the factory operates (FOB origin).
    // Used to auto-fill FOB Country on quote rows and to match the Trump 2025
    // reciprocal tariff rate when calculating duty.
    sequelize.query(`ALTER TABLE ${schema}"Factory" ADD COLUMN IF NOT EXISTS factory_country VARCHAR(255)`)
      .catch(err => console.warn('Migration Factory.factory_country skipped:', err.message));
    // One-time backfill: set factory_country from the most common vendor_country
    // among vendors linked to each factory. Only fills NULLs so it is safe to re-run.
    sequelize.query(`
      UPDATE ${schema}"Factory" f
      SET factory_country = sub.country
      FROM (
        SELECT factory_id_fk, vendor_country AS country,
               ROW_NUMBER() OVER (PARTITION BY factory_id_fk ORDER BY COUNT(*) DESC) AS rn
        FROM ${schema}vendor
        WHERE factory_id_fk IS NOT NULL AND vendor_country IS NOT NULL AND vendor_country <> ''
        GROUP BY factory_id_fk, vendor_country
      ) sub
      WHERE sub.rn = 1 AND sub.factory_id_fk = f.id
        AND (f.factory_country IS NULL OR f.factory_country = '')
    `).catch(err => console.warn('Backfill Factory.factory_country skipped:', err.message));
    // grid_cell_notes ŌĆö per-cell AG Grid notes keyed by grid_type + row_id + col_id.
    // Reusable across RFQ, Item Library, and License Tracking grids.
    sequelize.query(`CREATE TABLE IF NOT EXISTS ${schema}grid_cell_notes (
      id UUID PRIMARY KEY,
      grid_type VARCHAR(50) NOT NULL,
      row_id VARCHAR(255) NOT NULL,
      col_id VARCHAR(255) NOT NULL,
      note_text TEXT,
      note_author VARCHAR(255),
      note_read_only BOOLEAN NOT NULL DEFAULT false,
      created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
      updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
    )`).catch(err => console.warn('Migration grid_cell_notes skipped:', err.message));
    sequelize.query(`CREATE UNIQUE INDEX IF NOT EXISTS grid_cell_notes_grid_row_col_uq ON ${schema}grid_cell_notes (grid_type, row_id, col_id)`)
      .catch(err => console.warn('Migration grid_cell_notes_grid_row_col_uq skipped:', err.message));
    sequelize.query(`CREATE INDEX IF NOT EXISTS grid_cell_notes_grid_type_idx ON ${schema}grid_cell_notes (grid_type)`)
      .catch(err => console.warn('Migration grid_cell_notes_grid_type_idx skipped:', err.message));
}
module.exports = db;

