// ŌöĆŌöĆŌöĆ Buyer Target / Buyer Margin % (16 numeric columns) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

describe('RFQItem buyer target / buyer margin columns', () => {
  const TYPES = ['gen_fob', 'gen_mddp', 'gen_poe', 'gen_whse', 'lic_fob', 'lic_mddp', 'lic_poe', 'lic_whse'];
  const HEADERS = {
    gen_fob: 'Gen FOB', gen_mddp: 'Gen MDDP', gen_poe: 'Gen POE', gen_whse: 'Gen Whse',
    lic_fob: 'Lic FOB', lic_mddp: 'Lic MDDP', lic_poe: 'Lic POE', lic_whse: 'Lic Whse',
  };

  TYPES.forEach((t) => {
    ['buyer_target', 'buyer_margin'].forEach((suffix) => {
      const col = `rfqItem_${t}_${suffix}`;

      it(`model defines ${col} as DOUBLE`, () => {
        expect(rfqItemSource).toMatch(new RegExp(`${col}:\\s*\\{[\\s\\S]{0,60}DataTypes\\.DOUBLE`));
      });

      it(`db.js has a quoted ADD COLUMN IF NOT EXISTS migration for ${col} as DOUBLE PRECISION`, () => {
        expect(dbSource).toMatch(new RegExp(`ADD COLUMN IF NOT EXISTS\\s+"${col}"\\s+DOUBLE PRECISION`));
      });
    });

    it(`utility.js remaps + maps buyer fields for ${t}`, () => {
      const targetHdr = `${HEADERS[t]} Buyer Target`;
      const marginHdr = `${HEADERS[t]} Buyer Margin %`;
      // load (remapRFQItem)
      expect(utilitySource).toContain(`'${targetHdr}': item.dataValues.rfqItem_${t}_buyer_target`);
      expect(utilitySource).toContain(`'${marginHdr}': item.dataValues.rfqItem_${t}_buyer_margin`);
      // save (mapRFQItem) ŌĆö numeric-coerced
      expect(utilitySource).toContain(`'rfqItem_${t}_buyer_target': toNum(item['${targetHdr}'])`);
      expect(utilitySource).toContain(`'rfqItem_${t}_buyer_margin': toNum(item['${marginHdr}'])`);
    });
  });

  it('seeds the rfq_buyer_margin UI element idempotently', () => {
    expect(dbSource).toMatch(/INSERT INTO[\s\S]{0,40}"UIElements"[\s\S]{0,120}'rfq_buyer_margin'/);
    expect(dbSource).toMatch(/WHERE NOT EXISTS[\s\S]{0,120}"UIElements"[\s\S]{0,60}'rfq_buyer_margin'/);
  });

  it('grants the rfq_buyer_margin toggle to Adam Dweck by email, idempotently', () => {
    expect(dbSource).toContain("adweck@popcre.com");
    expect(dbSource).toMatch(/INSERT INTO[\s\S]{0,40}"RolePermissions"[\s\S]{0,400}adweck@popcre\.com/);
    expect(dbSource).toMatch(/NOT EXISTS[\s\S]{0,160}"RolePermissions"/);
  });
});

