/**
 * Single source of truth for what a saved RFQ view contains: column state,
 * filter model, and column-group open/closed state. Both "create new view"
 * (onSaveNewView) and "save current view" (onSaveLayout) go through here so a
 * new piece of view state can never be persisted by one path but not the other.
 */
private saveRfqViewState(viewName: string) {
  return this.itemService.saveGridViewState({
    grid_id: 'rfq',
    view_name: viewName,
    column_state: this.gridApi.getColumnState(),
    filter_model: this.gridApi.getFilterModel(),
    // Column-group open/closed state is separate from column state (AG Grid keeps
    // it in its own structure), so it must be captured explicitly here.
    column_group_state: this.gridApi.getColumnGroupState()
  });
}

